export default function App() {
  const [text, setText] = useState('a');
  const deferred = useDeferredValue(text);
  const stale = text !== deferred;
  return (
    <div style={{ fontFamily: 'sans-serif', padding: 24 }}>
      <input value={text} onChange={(e) => setText(e.target.value)} placeholder="Type fast" />
      <span style={{ opacity: stale ? 1 : 0, marginLeft: 8, color: '#888' }}>rendering…</span>
      <SlowList text={deferred} />
    </div>
  );
}

import { useSyncExternalStore } from 'react';

// A tiny store that lives OUTSIDE React.
let count = 0;
const listeners = new Set();
const store = {
  increment() { count++; listeners.forEach((l) => l()); },
  subscribe(l) { listeners.add(l); return () => listeners.delete(l); },
  getSnapshot() { return count; },
};

function Counter() {
  const value = useSyncExternalStore(store.subscribe, store.getSnapshot);
  return <h2>External count: {value}</h2>;
}

export default function App() {
  return (
    <div style={{ fontFamily: 'sans-serif', padding: 24 }}>
      <Counter />
      <Counter />
      <button onClick={() => store.increment()}>Increment store</button>
      <p style={{ color: '#666' }}>Both counters read one consistent snapshot — no tearing.</p>
    </div>
  );
}

import { useState, useEffect } from 'react';

export default function App() {
  const [correct, setCorrect] = useState(0);
  const [buggy, setBuggy] = useState(0);

  useEffect(() => {
    const id = setInterval(() => {
      setBuggy(buggy + 1);        // STALE: captures buggy=0 forever -> sticks at 1
      setCorrect((c) => c + 1);   // CORRECT: functional update reads latest
    }, 1000);
    return () => clearInterval(id);
  }, []); // empty deps on purpose, to expose the stale closure

  return (
    <div style={{ fontFamily: 'sans-serif', padding: 24 }}>
      <p>Functional update (climbs): <b>{correct}</b></p>
      <p>Stale closure (stuck at 1): <b>{buggy}</b></p>
    </div>
  );
}

