import { useState, useEffect } from 'react';

// Shorter queries resolve SLOWER, to force an out-of-order race.
function searchApi(q) {
  const delay = Math.max(200, 1200 - q.length * 150);
  return new Promise((res) => setTimeout(() => res(q ? 'Results for: ' + q : '—'), delay));
}

export default function App() {
  const [query, setQuery] = useState('');
  const [result, setResult] = useState('');

  useEffect(() => {
    let active = true;
    searchApi(query).then((r) => { if (active) setResult(r); }); // ignore if superseded
    return () => { active = false; };
  }, [query]);

  return (
    <div style={{ fontFamily: 'sans-serif', padding: 24 }}>
      <input value={query} onChange={(e) => setQuery(e.target.value)} placeholder="Type quickly" />
      <p>{result}</p>
      <p style={{ color: '#666' }}>The cleanup flag stops a slow early request from overwriting newer results.</p>
    </div>
  );
}

import { useState } from 'react';

export default function App() {
  const [todos, setTodos] = useState([{ id: 1, text: 'Learn immutability' }]);
  const [text, setText] = useState('');

  function addCorrect() {
    if (!text.trim()) return;
    setTodos((prev) => [...prev, { id: Date.now(), text }]); // NEW array -> re-renders
    setText('');
  }
  function addBroken() {
    todos.push({ id: Date.now(), text: text || 'mutated' }); // same reference -> no re-render
    setText('');
  }

  return (
    <div style={{ fontFamily: 'sans-serif', padding: 24 }}>
      <input value={text} onChange={(e) => setText(e.target.value)} />
      <button onClick={addCorrect}>Add (immutable)</button>{' '}
      <button onClick={addBroken}>Add (mutate — UI won't update)</button>
      <ul>{todos.map((t) => <li key={t.id}>{t.text}</li>)}</ul>
    </div>
  );
}

