import { useState, useTransition } from 'react';

function saveToServer(value) {
  return new Promise((res, rej) =>
    setTimeout(() => (value % 2 === 0 ? res('Saved ' + value) : rej(new Error('Odd numbers rejected'))), 800),
  );
}

export default function App() {
  const [count, setCount] = useState(0);
  const [status, setStatus] = useState('');
  const [isPending, startTransition] = useTransition();

  function save() {
    // An async function inside startTransition IS an Action: pending is tracked.
    startTransition(async () => {
      try { setStatus(await saveToServer(count)); }
      catch (e) { setStatus('Error: ' + e.message); }
    });
  }

  return (
    <div style={{ fontFamily: 'sans-serif', padding: 24 }}>
      <p>Count: {count}</p>
      <button onClick={() => setCount((c) => c + 1)}>+1</button>{' '}
      <button onClick={save} disabled={isPending}>{isPending ? 'Saving…' : 'Save (even only)'}</button>
      <p>{status}</p>
    </div>
  );
}

import { useActionState } from 'react';

// Pretend this calls your backend.
function fakeUpdate(name) {
  return new Promise((resolve) =>
    setTimeout(() => resolve(name.trim() ? 'Saved: ' + name : 'Name is required'), 800),
  );
}

export default function App() {
  const [message, submitAction, isPending] = useActionState(
    async (prev, formData) => await fakeUpdate(formData.get('name')),
    'No changes yet',
  );
  return (
    <div style={{ fontFamily: 'sans-serif', padding: 24 }}>
      <form action={submitAction}>
        <input name="name" placeholder="Your name" />
        <button disabled={isPending}>{isPending ? 'Saving…' : 'Save'}</button>
      </form>
      <p>{message}</p>
    </div>
  );
}

